local p = {}
--Returns the target of {{Category redirect}}, if it exists, else returns the original cat. function p.rtarget( cat, frame ) if string.match( cat, '[|]' ) then return cat end cat = string.gsub(cat, '^[Cc]ategory:', '') --"!" in cat not recognized by mw.title.makeTitle() otherwise local catcontent = mw.title.makeTitle( 'Category', cat or '' ):getContent() if string.match( catcontent or '', '{{ *[Cc]at' ) then local getRegex = require('Module:Template redirect regex').main local tregex = getRegex('Category redirect') for _, v in pairs (tregex) do local rtarget = mw.ustring.match( catcontent, v..'%s*|%s*([^|]+)' ) if rtarget then if string.match(rtarget, '{{') then --{{Title year}}, etc., exists; evaluate local regex_ty = '%s*|%s*([^{}]*{{([^{|}]+)}}[^{}]-)%s*}}' --eval null-param templates only; expanded if/as needed; $1 nests $2 local rtarget_orig, ty = mw.ustring.match( catcontent, v..regex_ty ) if rtarget_orig then local ty_eval = frame:expandTemplate{ title = ty, args = { page = cat } } --frame:newChild doesn't work, use 'page' param instead local rtarget_eval = mw.ustring.gsub(rtarget_orig, '{{%s*'..ty..'%s*}}', ty_eval ) return rtarget_eval else --TODO: 1) +loop for multiple templates, 2) allow sub-parameters return cat end else --normal, plain text target rtarget = mw.ustring.gsub(rtarget, '^1%s*=%s*', '') rtarget = string.gsub(rtarget, '^[Cc]ategory:', '') rtarget = mw.ustring.gsub(rtarget, '%s*}}', '') return rtarget end end end end return cat end
function p.main( frame ) local args = frame:getParent().args local cat = mw.text.trim( args[1] or '' )
if (cat == '') or (cat == nil) then return '' end return p.rtarget( cat, frame ) end
return p
